package com.taskflow.security;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.test.web.servlet.MockMvc;

import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

/**
 * Integration tests for SecurityConfig filter chain configuration.
 *
 * Verifies:
 * - /api/auth/** endpoints are publicly accessible (permitAll)
 * - Other /api/** endpoints require authentication (401 without token)
 * - H2 console is accessible (permitAll)
 * - JWT filter is integrated into the filter chain
 *
 * Uses full Spring Boot context with MockMvc.
 */
@SpringBootTest
@AutoConfigureMockMvc
@ActiveProfiles("test")
@DisplayName("SecurityConfig Integration Tests")
class SecurityConfigIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Nested
    @DisplayName("Public Endpoints (permitAll)")
    class PublicEndpoints {

        @Test
        @DisplayName("should permit POST /api/auth/register without authentication")
        void shouldPermitRegisterWithoutAuth() throws Exception {
            mockMvc.perform(post("/api/auth/register")
                            .contentType("application/json")
                            .content("{\"username\":\"test\",\"password\":\"password123\",\"displayName\":\"Test\"}"))
                    .andExpect(status().isNot(org.hamcrest.Matchers.equalTo(401)));
            // Note: may return 404 if controller not implemented, but NOT 401
        }

        @Test
        @DisplayName("should permit POST /api/auth/login without authentication")
        void shouldPermitLoginWithoutAuth() throws Exception {
            mockMvc.perform(post("/api/auth/login")
                            .contentType("application/json")
                            .content("{\"username\":\"test\",\"password\":\"password123\"}"))
                    .andExpect(status().isNot(org.hamcrest.Matchers.equalTo(401)));
        }
    }

    @Nested
    @DisplayName("Protected Endpoints (require authentication)")
    class ProtectedEndpoints {

        @Test
        @DisplayName("should return 401 for GET /api/tasks without token")
        void shouldReturn401ForTasksWithoutToken() throws Exception {
            mockMvc.perform(get("/api/tasks"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should return 401 for POST /api/tasks without token")
        void shouldReturn401ForPostTasksWithoutToken() throws Exception {
            mockMvc.perform(post("/api/tasks")
                            .contentType("application/json")
                            .content("{\"title\":\"Test Task\"}"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should permit GET /api/auth/me at security filter level (permitAll on /api/auth/**)")
        void shouldPermitAuthMeAtSecurityFilterLevel() throws Exception {
            // /api/auth/me is under /api/auth/** which is permitAll in SecurityConfig.
            // The 401 for unauthenticated /api/auth/me comes from the controller, not the security filter.
            // So the security filter should NOT block this request.
            mockMvc.perform(get("/api/auth/me"))
                    .andExpect(status().isNot(org.hamcrest.Matchers.equalTo(403)));
            // Note: may return 404 (no controller) or 401 (controller-level check), but NOT 403 (forbidden by security)
        }
    }

    @Nested
    @DisplayName("JWT Filter Integration")
    class JwtFilterIntegration {

        @Test
        @DisplayName("should return 401 when Authorization header has invalid token")
        void shouldReturn401WithInvalidToken() throws Exception {
            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer invalid.jwt.token"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("should return 401 when Authorization header has expired token")
        void shouldReturn401WithExpiredToken() throws Exception {
            // An obviously invalid/expired token
            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiIxIiwiZXhwIjoxfQ.invalid"))
                    .andExpect(status().isUnauthorized());
        }
    }

    @Nested
    @DisplayName("Stateless Session Policy")
    class StatelessSessionPolicy {

        @Test
        @DisplayName("should not create HTTP session for requests")
        void shouldNotCreateSession() throws Exception {
            mockMvc.perform(get("/api/tasks"))
                    .andExpect(result -> {
                        // Session should not be created for stateless config
                        org.assertj.core.api.Assertions.assertThat(
                                result.getRequest().getSession(false)
                        ).isNull();
                    });
        }
    }
}

