package com.taskflow.service;

import com.taskflow.dto.CreateTaskRequest;
import com.taskflow.dto.TransitionsResponse;
import com.taskflow.dto.UpdateTaskRequest;
import com.taskflow.entity.Task;
import com.taskflow.entity.TaskStatus;
import com.taskflow.exception.InvalidTransitionException;
import com.taskflow.exception.ResourceNotFoundException;
import com.taskflow.repository.TaskRepository;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.data.domain.Sort;

import java.time.LocalDateTime;
import java.util.List;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class TaskService {

    private final TaskRepository taskRepository;

    public TaskService(TaskRepository taskRepository) {
        this.taskRepository = taskRepository;
    }

    @Transactional
    public Task create(CreateTaskRequest request, Long userId) {
        Task task = new Task();
        task.setTitle(request.getTitle());
        task.setDescription(request.getDescription());
        task.setPriority(request.getPriority());
        task.setCreatedBy(userId);
        return taskRepository.save(task);
    }

    @Transactional(readOnly = true)
    public Task getById(Long id) {
        Task task = taskRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Task not found with id: " + id));
        if (task.isDeleted()) {
            throw new ResourceNotFoundException("Task not found with id: " + id);
        }
        return task;
    }

    @Transactional
    public Task update(Long id, UpdateTaskRequest request) {
        Task task = getById(id);
        task.setTitle(request.getTitle());
        task.setDescription(request.getDescription());
        if (request.getPriority() != null) {
            task.setPriority(request.getPriority());
        }
        return taskRepository.save(task);
    }

    @Transactional
    public void softDelete(Long id) {
        Task task = getById(id);
        task.setDeleted(true);
        taskRepository.save(task);
    }

    @Transactional(readOnly = true)
    public Page<Task> list(String keyword, Task.Priority priority, int page, int size) {
        Pageable pageable = PageRequest.of(page, size, Sort.by(Sort.Direction.DESC, "createdAt"));

        if (keyword != null && !keyword.isBlank() && priority != null) {
            return taskRepository.findByDeletedFalseAndTitleContainingIgnoreCaseAndPriority(keyword, priority, pageable);
        } else if (keyword != null && !keyword.isBlank()) {
            return taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase(keyword, pageable);
        } else if (priority != null) {
            return taskRepository.findByDeletedFalseAndPriority(priority, pageable);
        } else {
            return taskRepository.findByDeletedFalse(pageable);
        }
    }

    @Transactional
    public Task transitionStatus(Long id, TaskStatus target) {
        Task task = getById(id);
        if (!task.getStatus().canTransitionTo(target)) {
            throw new InvalidTransitionException(
                    "Cannot transition from " + task.getStatus() + " to " + target);
        }
        task.setStatus(target);
        task.setUpdatedAt(LocalDateTime.now());
        return taskRepository.save(task);
    }

    @Transactional(readOnly = true)
    public TransitionsResponse getAvailableTransitions(Long id) {
        Task task = getById(id);
        List<String> transitions = task.getStatus().getAllowedTransitions().stream()
                .map(TaskStatus::name)
                .toList();
        TransitionsResponse response = new TransitionsResponse();
        response.setCurrentStatus(task.getStatus().name());
        response.setAvailableTransitions(transitions);
        return response;
    }
}

