package com.taskflow.service;

import com.taskflow.dto.CreateTaskRequest;
import com.taskflow.dto.UpdateTaskRequest;
import com.taskflow.entity.Task;
import com.taskflow.entity.TaskStatus;
import com.taskflow.repository.TaskRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.data.domain.Page;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

/**
 * Integration tests for TaskService.
 *
 * Tests will FAIL until TaskService is implemented.
 * Tests service layer logic: create, getById, update, softDelete, list with filters.
 */
@SpringBootTest
@DisplayName("TaskService Integration Tests")
class TaskServiceTest {

    @Autowired
    private TaskService taskService;

    @Autowired
    private TaskRepository taskRepository;

    private static final Long TEST_USER_ID = 1L;

    @BeforeEach
    void setUp() {
        taskRepository.deleteAll();
    }

    private CreateTaskRequest buildCreateRequest(String title, String desc, Task.Priority priority) {
        CreateTaskRequest req = new CreateTaskRequest();
        req.setTitle(title);
        req.setDescription(desc);
        if (priority != null) {
            req.setPriority(priority);
        }
        return req;
    }

    // ── Create ──────────────────────────────────────────────────────────

    @Nested
    @DisplayName("create — task creation")
    class CreateTests {

