    private TaskService taskService;

    @Autowired
    private TaskRepository taskRepository;

    private static final Long TEST_USER_ID = 1L;

    @BeforeEach
    void setUp() {
        taskRepository.deleteAll();
    }

    private CreateTaskRequest buildCreateRequest(String title, String desc, Task.Priority priority) {
        CreateTaskRequest req = new CreateTaskRequest();
        req.setTitle(title);
        req.setDescription(desc);
        if (priority != null) {
            req.setPriority(priority);
        }
        return req;
    }

    // ── Create ──────────────────────────────────────────────────────────

    @Nested
    @DisplayName("create — task creation")
    class CreateTests {

        @Test
        @DisplayName("Should create task with all fields populated")
        void shouldCreateTaskWithAllFields() {
            CreateTaskRequest req = buildCreateRequest("Test Task", "Test desc", Task.Priority.HIGH);
            Task created = taskService.create(req, TEST_USER_ID);

            assertThat(created).isNotNull();
            assertThat(created.getId()).isNotNull();
            assertThat(created.getTitle()).isEqualTo("Test Task");
            assertThat(created.getDescription()).isEqualTo("Test desc");
            assertThat(created.getPriority()).isEqualTo(Task.Priority.HIGH);
            assertThat(created.getStatus()).isEqualTo(TaskStatus.TODO);
            assertThat(created.getCreatedBy()).isEqualTo(TEST_USER_ID);
            assertThat(created.getCreatedAt()).isNotNull();
            assertThat(created.isDeleted()).isFalse();
        }

        @Test
        @DisplayName("Should set createdBy from provided userId")
        void shouldSetCreatedByFromUserId() {
            CreateTaskRequest req = buildCreateRequest("Task", "desc", Task.Priority.MEDIUM);
            Task created = taskService.create(req, 42L);
            assertThat(created.getCreatedBy()).isEqualTo(42L);
        }

        @Test
        @DisplayName("Should default priority to MEDIUM when not specified")
        void shouldDefaultPriorityToMedium() {
            CreateTaskRequest req = new CreateTaskRequest();
            req.setTitle("Task without priority");
            // priority defaults to MEDIUM in CreateTaskRequest
            Task created = taskService.create(req, TEST_USER_ID);
            assertThat(created.getPriority()).isEqualTo(Task.Priority.MEDIUM);
        }

        @Test
        @DisplayName("Should set initial status to TODO")
        void shouldSetInitialStatusToTodo() {
            CreateTaskRequest req = buildCreateRequest("Task", "desc", Task.Priority.LOW);
            Task created = taskService.create(req, TEST_USER_ID);
            assertThat(created.getStatus()).isEqualTo(TaskStatus.TODO);
        }
    }

    // ── GetById ─────────────────────────────────────────────────────────

    @Nested
    @DisplayName("getById — retrieve task")
    class GetByIdTests {

        @Test
        @DisplayName("Should return task when it exists and is not deleted")
        void shouldReturnExistingTask() {
            CreateTaskRequest req = buildCreateRequest("Find Me", "desc", Task.Priority.HIGH);
            Task created = taskService.create(req, TEST_USER_ID);

            Task found = taskService.getById(created.getId());
            assertThat(found).isNotNull();
            assertThat(found.getId()).isEqualTo(created.getId());
            assertThat(found.getTitle()).isEqualTo("Find Me");
        }

        @Test
        @DisplayName("Should throw exception for non-existent task ID")
        void shouldThrowForNonExistentTask() {
            assertThatThrownBy(() -> taskService.getById(99999L))
                    .isInstanceOf(RuntimeException.class);
        }

        @Test
        @DisplayName("Should throw exception for soft-deleted task")
        void shouldThrowForSoftDeletedTask() {
            CreateTaskRequest req = buildCreateRequest("Delete Me", "desc", Task.Priority.MEDIUM);
            Task created = taskService.create(req, TEST_USER_ID);
            taskService.softDelete(created.getId());

            assertThatThrownBy(() -> taskService.getById(created.getId()))
                    .isInstanceOf(RuntimeException.class);
        }
    }

    // ── Update ──────────────────────────────────────────────────────────

    @Nested
    @DisplayName("update — modify task")
    class UpdateTests {

        @Test
        @DisplayName("Should update task title and description")
        void shouldUpdateTitleAndDescription() {
            CreateTaskRequest createReq = buildCreateRequest("Original", "Original desc", Task.Priority.LOW);
            Task created = taskService.create(createReq, TEST_USER_ID);

            UpdateTaskRequest updateReq = new UpdateTaskRequest();
            updateReq.setTitle("Updated Title");
            updateReq.setDescription("Updated desc");
            updateReq.setPriority(Task.Priority.HIGH);

            Task updated = taskService.update(created.getId(), updateReq);
            assertThat(updated.getTitle()).isEqualTo("Updated Title");
            assertThat(updated.getDescription()).isEqualTo("Updated desc");
            assertThat(updated.getPriority()).isEqualTo(Task.Priority.HIGH);
        }

        @Test
        @DisplayName("Should set updatedAt on update")
        void shouldSetUpdatedAt() {
            CreateTaskRequest createReq = buildCreateRequest("Original", "desc", Task.Priority.MEDIUM);
            Task created = taskService.create(createReq, TEST_USER_ID);

            UpdateTaskRequest updateReq = new UpdateTaskRequest();
            updateReq.setTitle("Updated");
            updateReq.setDescription("desc");

            Task updated = taskService.update(created.getId(), updateReq);
            assertThat(updated.getUpdatedAt()).isNotNull();
        }

        @Test
        @DisplayName("Should throw exception when updating non-existent task")
        void shouldThrowWhenUpdatingNonExistent() {
            UpdateTaskRequest updateReq = new UpdateTaskRequest();
            updateReq.setTitle("Updated");

            assertThatThrownBy(() -> taskService.update(99999L, updateReq))
                    .isInstanceOf(RuntimeException.class);
        }
    }

    // ── Soft Delete ─────────────────────────────────────────────────────

    @Nested
    @DisplayName("softDelete — mark task as deleted")
    class SoftDeleteTests {

        @Test
        @DisplayName("Should mark task as deleted")
        void shouldMarkTaskAsDeleted() {
            CreateTaskRequest req = buildCreateRequest("Delete Me", "desc", Task.Priority.MEDIUM);
            Task created = taskService.create(req, TEST_USER_ID);

            taskService.softDelete(created.getId());

            Task deleted = taskRepository.findById(created.getId()).orElse(null);
            assertThat(deleted).isNotNull();
            assertThat(deleted.isDeleted()).isTrue();
        }

        @Test
        @DisplayName("Should throw exception when deleting non-existent task")
        void shouldThrowWhenDeletingNonExistent() {
            assertThatThrownBy(() -> taskService.softDelete(99999L))
                    .isInstanceOf(RuntimeException.class);
        }
    }

    // ── List (paginated + filters) ──────────────────────────────────────

    @Nested
    @DisplayName("list — paginated task listing with filters")
    class ListTests {

        @Test
        @DisplayName("Should return paginated results excluding deleted tasks")
        void shouldReturnPaginatedResults() {
            for (int i = 0; i < 5; i++) {
                taskService.create(buildCreateRequest("Task " + i, "desc", Task.Priority.MEDIUM), TEST_USER_ID);
            }

            // Create and delete one task
            Task toDelete = taskService.create(buildCreateRequest("Deleted", "desc", Task.Priority.MEDIUM), TEST_USER_ID);
            taskService.softDelete(toDelete.getId());

            Page<Task> result = taskService.list(null, null, null, 0, 20);
            assertThat(result.getTotalElements()).isEqualTo(5);
            assertThat(result.getContent()).hasSize(5);
        }

        @Test
        @DisplayName("Should filter by keyword (case-insensitive)")
        void shouldFilterByKeyword() {
            taskService.create(buildCreateRequest("Build login page", "desc", Task.Priority.HIGH), TEST_USER_ID);
            taskService.create(buildCreateRequest("Fix LOGIN bug", "desc", Task.Priority.MEDIUM), TEST_USER_ID);
            taskService.create(buildCreateRequest("Design dashboard", "desc", Task.Priority.LOW), TEST_USER_ID);

            Page<Task> result = taskService.list("login", null, null, 0, 20);
            assertThat(result.getTotalElements()).isEqualTo(2);
        }

        @Test
        @DisplayName("Should filter by priority")
        void shouldFilterByPriority() {
            taskService.create(buildCreateRequest("High 1", "desc", Task.Priority.HIGH), TEST_USER_ID);
            taskService.create(buildCreateRequest("High 2", "desc", Task.Priority.HIGH), TEST_USER_ID);
            taskService.create(buildCreateRequest("Medium", "desc", Task.Priority.MEDIUM), TEST_USER_ID);

            Page<Task> result = taskService.list(null, Task.Priority.HIGH, null, 0, 20);
            assertThat(result.getTotalElements()).isEqualTo(2);
            result.getContent().forEach(t ->
                    assertThat(t.getPriority()).isEqualTo(Task.Priority.HIGH));
        }

        @Test
        @DisplayName("Should filter by keyword AND priority")
        void shouldFilterByKeywordAndPriority() {
            taskService.create(buildCreateRequest("Build login", "desc", Task.Priority.HIGH), TEST_USER_ID);
            taskService.create(buildCreateRequest("Build dashboard", "desc", Task.Priority.MEDIUM), TEST_USER_ID);
            taskService.create(buildCreateRequest("Fix login", "desc", Task.Priority.HIGH), TEST_USER_ID);

            Page<Task> result = taskService.list("build", Task.Priority.HIGH, null, 0, 20);
            assertThat(result.getTotalElements()).isEqualTo(1);
        }

        @Test
        @DisplayName("Should paginate correctly with custom page and size")
        void shouldPaginateCorrectly() {
            for (int i = 0; i < 12; i++) {
                taskService.create(buildCreateRequest("Task " + i, "desc", Task.Priority.MEDIUM), TEST_USER_ID);
            }

            Page<Task> page0 = taskService.list(null, null, 0, 5);
            assertThat(page0.getContent()).hasSize(5);
            assertThat(page0.getTotalElements()).isEqualTo(12);
            assertThat(page0.getTotalPages()).isEqualTo(3);

            Page<Task> page2 = taskService.list(null, null, 2, 5);
            assertThat(page2.getContent()).hasSize(2); // last page: 12 - 10 = 2
        }
    }
}

