@DisplayName("TaskService Integration Tests")
class TaskServiceTest {

    @Autowired
    private TaskService taskService;

    @Autowired
    private TaskRepository taskRepository;

    private static final Long TEST_USER_ID = 1L;

    @BeforeEach
    void setUp() {
