    @Nested
    @DisplayName("list — paginated task listing with filters")
    class ListTests {

        @Test
        @DisplayName("Should return paginated results excluding deleted tasks")
        void shouldReturnPaginatedResults() {
            for (int i = 0; i < 5; i++) {
                taskService.create(buildCreateRequest("Task " + i, "desc", Task.Priority.MEDIUM), TEST_USER_ID);
