import json, os, glob

for f in sorted(glob.glob('agent-a*.jsonl')):
    agent_id = f.replace('agent-','').replace('.jsonl','')
    meta_f = f.replace('.jsonl','.meta.json')
    meta_type = 'unknown'
    if os.path.exists(meta_f):
        try:
            meta_type = json.load(open(meta_f))['agentType']
        except: pass

    size = os.path.getsize(f)

    # Get first prompt
    desc = '(no description)'
    try:
        with open(f,'r',encoding='utf-8') as fh:
            first_line = fh.readline()
            obj = json.loads(first_line)
            if obj.get('type') == 'summary':
                desc = 'CONTEXT-COMPACT'
            else:
                for msg in obj.get('messages',[]):
                    if msg.get('role') == 'user':
                        content = msg.get('content','')
                        if isinstance(content, list):
                            for block in content:
                                if isinstance(block, dict) and block.get('type') == 'tool_result':
                                    for sub in block.get('content',[]):
                                        if isinstance(sub, dict) and sub.get('type') == 'text':
                                            desc = sub['text'][:150]
                                            break
                                elif isinstance(block, dict) and block.get('type') == 'text':
                                    desc = block['text'][:150]
                                    break
                            if desc != '(no description)': break
                        else:
                            desc = str(content)[:150]
                            break
    except Exception as e:
        desc = f'(error: {e})'

    print(f'{agent_id} | {meta_type} | {size//1024}KB | {desc}')
"

