for (const f of files) {
  const id = f.replace('agent-','').replace('.jsonl','');
  const metaF = f.replace('.jsonl','.meta.json');
  let metaType = 'unknown';
  try { metaType = JSON.parse(fs.readFileSync(metaF,'utf8')).agentType; } catch(e) {}
  const size = fs.statSync(f).size;
  const mtime = fs.statSync(f).mtime.toISOString().substr(11,8);

  let desc = '(?)';
  try {
    const firstLine = fs.readFileSync(f,'utf8').split('\n')[0];
    const obj = JSON.parse(firstLine);
    if (obj.type === 'summary') { desc = 'CONTEXT-COMPACT'; }
    else {
      const msgs = obj.messages || [];
      for (const m of msgs) {
        if (m.role === 'user') {
          const c = m.content;
          if (Array.isArray(c)) {
            for (const b of c) {
              if (b.type === 'text' && b.text) { desc = b.text.substring(0,140); break; }
              if (b.type === 'tool_result' && Array.isArray(b.content)) {
                for (const s of b.content) {
                  if (s.type === 'text') { desc = s.text.substring(0,140); break; }
                }
                if (desc !== '(?)') break;
              }
            }
          } else { desc = String(c).substring(0,140); }
          if (desc !== '(?)') break;
        }
      }
    }
  } catch(e) { desc = '(parse error)'; }
  console.log(id + ' | ' + metaType + ' | ' + Math.round(size/1024) + 'KB | ' + mtime + ' | ' + desc.replace(/\\n/g,' '));
}
"

